const msg = $input.first().json.message;
const testo = (msg.text || '').trim();
const chatId = msg.chat.id;
const nome = msg.from.first_name || 'utente';

// Parsing comandi
// Formato atteso:
// /avviso Domani siamo chiusi
// /promo Menù pranzo 12€ - Primo+secondo+acqua
// /orari Lun-Ven 08:00-20:00 | Sab 09:00-14:00
// /telefono 02 1234567
// /info parcheggio Disponibile in via Roma
// /menu aggiungi Primi | Spaghetti al pomodoro | | 10
// /menu rimuovi Primi | Spaghetti al pomodoro
// /stato  (mostra riepilogo dati)

const righe = testo.split('\n');
const prima = righe[0];
const parti = prima.split(' ');
const comando = parti[0].toLowerCase();
const resto = parti.slice(1).join(' ');

return [{
  json: {
    chatId,
    nome,
    comando,
    resto,
    testoCompleto: testo
  }
}];

const chatId = $json.chatId;
const res = await fetch('http://host.docker.internal:3001/cliente/' + chatId, { method: 'PATCH', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({ campo: 'avviso', valore: $json.resto }) });
const r = await res.json();
if (!res.ok) throw new Error(r.errore || 'Errore');
return [{ json: { ok: true, campo: 'avviso', chatId } }];

const chatId = $json.chatId;
const res = await fetch('http://host.docker.internal:3001/cliente/' + chatId, { method: 'PATCH', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({ campo: 'promo', valore: $json.resto }) });
const r = await res.json();
if (!res.ok) throw new Error(r.errore || 'Errore');
return [{ json: { ok: true, campo: 'promozione', chatId } }];

const chatId = $json.chatId;
const res = await fetch('http://host.docker.internal:3001/cliente/' + chatId, { method: 'PATCH', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({ campo: 'orari', valore: $json.resto }) });
const r = await res.json();
if (!res.ok) throw new Error(r.errore || 'Errore');
return [{ json: { ok: true, campo: 'orari', chatId } }];

const chatId = $json.chatId;
const res = await fetch('http://host.docker.internal:3001/cliente/' + chatId, { method: 'PATCH', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({ campo: 'telefono', valore: $json.resto }) });
const r = await res.json();
if (!res.ok) throw new Error(r.errore || 'Errore');
return [{ json: { ok: true, campo: 'telefono', chatId } }];

const chatId = $json.chatId;
const res = await fetch('http://host.docker.internal:3001/cliente/' + chatId);
if (!res.ok) return [{ json: { chatId, testo: 'Sito non trovato.' } }];
const d = await res.json();
const orariStr = d.orari.map(o => o.giorno + ': ' + o.ore).join('
');
const testo = 'Stato: ' + d.nome + '
' + d.indirizzo + '
' + d.telefono + '
Orari:
' + orariStr + '
Avviso: ' + (d.avviso || 'nessuno') + '
Promo: ' + (d.promozione?.attiva ? d.promozione.testo : 'nessuna');
return [{ json: { chatId, testo } }];

// Unifica la risposta da tutti i rami
const input = $input.first().json;
let testo;

if (input.testo) {
  testo = input.testo; // già formattato (stato/aiuto)
} else if (input.ok) {
  const etichette = {
    avviso: '📢 Avviso',
    promozione: '🎉 Promozione',
    orari: '🕐 Orari',
    telefono: '📞 Telefono'
  };
  testo = `✅ *${etichette[input.campo] || input.campo} aggiornato!*\n\nIl sito è già live con le modifiche.`;
} else {
  testo = '❌ Comando non riconosciuto. Scrivi /aiuto per vedere i comandi disponibili.';
}

return [{ json: { chatId: input.chatId, testo } }];

